import React, { useState } from 'react';

const App = () => {
  const [channels, setChannels] = useState(['General', 'Sales', 'Marketing']);
  const [selectedChannel, setSelectedChannel] = useState('General');
  const [messages, setMessages] = useState({ General: [], Sales: [], Marketing: [] });
  const [searchTerm, setSearchTerm] = useState('');

  const handleChannelChange = (channel) => setSelectedChannel(channel);
  const handleSearchInputChange = (event) => setSearchTerm(event.target.value);

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <button onClick={() => handleChannelChange('General')} className="bg-[#C06C88] hover:bg-[#B7D7CD] text-[#B7D7CD] hover:text-white px-4 py-2 rounded">General</button>
      <button onClick={() => handleChannelChange('Sales')} className="bg-[#C06C88] hover:bg-[#B7D7CD] text-[#B7D7CD] hover:text-white px-4 py-2 rounded">Sales</button>
      <button onClick={() => handleChannelChange('Marketing')} className="bg-[#C06C88] hover:bg-[#B7D7CD] text-[#B7D7CD] hover:text-white px-4 py-2 rounded">Marketing</button>
      <input onChange={handleSearchInputChange} className="px-4 py-2 rounded" placeholder="Search"></input>
      <ul>
        {channels.map((channel) => (
          <li key={channel} className="bg-[#B7D7CD] hover:bg-[#C06C88] text-[#C06C88] hover:text-white p-4 cursor-pointer" onClick={() => handleChannelChange(channel)}>
            {channel}
          </li>
        ))}
      </ul>
      <div>
        {messages[selectedChannel].map((message, index) => (
          <p key={index} className="bg-[#411C56] hover:bg-[#C06C88] text-[#C06C88] hover:text-white p-4 mb-2" style="background-color: #{'#C06C88'.replace(/#/, '').slice(0, 6)}">
            {message}
          </p>
        ))}
      </div>
    </div>
  );
};

export default App;
